import React, { useContext } from 'react';
import { useParams } from 'react-router-dom';
import { CartContext } from '../context/CartContext';
import LoadingSpinner from '../components/LoadingSpinner';

const ProductPage = () => {
  const { productId } = useParams();
  const { addToCart } = useContext(CartContext);
  const [product, setProduct] = React.useState(null);
  const [loading, setLoading] = React.useState(true);

  React.useEffect(() => {
    // Fetch product details
    const fetchProduct = async () => {
      try {
        const response = await fetch(`/api/products/${productId}`);
        const data = await response.json();
        setProduct(data);
      } catch (error) {
        console.error('Error fetching product:', error);
      } finally {
        setLoading(false);
      }
    };
    fetchProduct();
  }, [productId]);

  if (loading) return <LoadingSpinner />;
  if (!product) return <div>Product not found</div>;

  return (
    <div className="max-w-6xl mx-auto px-4 py-8">
      <div className="flex flex-col md:flex-row gap-8">
        <div className="flex-1">
          <img src={product?.image || 'https://images.unsplash.com/photo-1506744038136-46273834b3fb?w=400'} alt={product?.name} className="w-full h-auto rounded-xl" />
        </div>
        <div className="flex-1">
          <h1 className="text-3xl font-bold mb-4">{product?.name ?? 'Product Name'}</h1>
          <p className="text-gray-400 mb-4">{product?.description ?? 'Product description goes here.'}</p>
          <p className="text-xl font-semibold mb-4">${product?.price ?? 0}</p>
          <button onClick={() => addToCart(product)} className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition">Add to Cart</button>
        </div>
      </div>
    </div>
  );
};

export default ProductPage;

