import React, { useContext } from 'react';
import { CartContext } from '../context/CartContext';
import CartItem from '../components/CartItem';

const CartPage = () => {
  const { cartItems, removeFromCart } = useContext(CartContext);

  if (!cartItems || cartItems.length === 0) return <div>Your cart is empty</div>;

  return (
    <div className="max-w-6xl mx-auto px-4 py-8">
      <h1 className="text-3xl font-bold mb-8">Your Shopping Cart</h1>
      <div className="grid grid-cols-1 gap-6">
        {(cartItems ?? []).map(item => (
          <CartItem key={item.id} item={item} onRemove={() => removeFromCart(item.id)} />
        ))}
      </div>
      <button className="mt-8 px-4 py-2 rounded-lg bg-green-600 text-white hover:bg-green-500 transition">Proceed to Checkout</button>
    </div>
  );
};

export default CartPage;
